import React, { useState, useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import "./ProductDetails.css";

const ProductDetails = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const [activeImage, setActiveImage] = useState(0);

  // سحب المنتج من الـ state المرسل
  const product = location.state?.product;

  // العودة للخلف
  const handleBack = () => navigate(-1);

  // التمرير لأعلى الصفحة عند فتحها
  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  if (!product) {
    return (
      <div
        style={{
          textAlign: "center",
          padding: "100px",
          fontFamily: "sans-serif",
        }}
      >
        <h2>عذراً، لم يتم العثور على المنتج</h2>
        <button
          onClick={() => navigate("/")}
          style={{ padding: "10px 20px", marginTop: "20px", cursor: "pointer" }}
        >
          العودة للرئيسية
        </button>
      </div>
    );
  }

  return (
    <div className="product-details-page">
      <div className="sticky-header">
        <button
          onClick={handleBack}
          className="back-button-new"
          aria-label="الرجوع"
        >
          <svg
            xmlns="http://www.w3.org/2000/svg"
            width="20"
            height="20"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M9 5l7 7-7 7"
            />
          </svg>
          <span>الرجوع للخلف</span>
        </button>
        <h2 className="header-title">تفاصيل المنتج</h2>
        <div className="header-spacer"></div>
      </div>

      <div className="product-container">
        <div className="product-main-grid">
          <div className="image-gallery-section">
            <div className="main-image-wrapper">
              <img
                key={activeImage}
                src={product.images ? product.images[activeImage] : product.img}
                alt={product.name}
                className="main-image fade-animation"
              />
            </div>

            {product.images && product.images.length > 1 && (
              <div className="thumbnail-list">
                {product.images.map((img, idx) => (
                  <button
                    key={idx}
                    onClick={() => setActiveImage(idx)}
                    className={`thumbnail-btn ${
                      activeImage === idx ? "active" : ""
                    }`}
                  >
                    <img src={img} alt="thumbnail" />
                  </button>
                ))}
              </div>
            )}
          </div>

          <div className="product-info-section">
            <div className="info-header">
              <h1 className="product-name-h1">{product.name}</h1>
            </div>

            <div className="details-stack">
              <section className="info-section-item">
                <h3 className="section-title">
                  <span className="title-indicator"></span>
                  عن المنتج
                </h3>
                <p className="description-text">
                  {product.description || product.desc}
                </p>
              </section>

              <div className="specs-grid">
                <div className="spec-card weight">
                  <h4 className="spec-label">الوزن الصافي</h4>
                  <p className="spec-value">{product.weight || "غير محدد"}</p>
                </div>
                <div className="spec-card packaging">
                  <h4 className="spec-label">نوع التعبئة</h4>
                  <p className="spec-value">
                    {product.packaging || "تعبئة مصنعية"}
                  </p>
                </div>
              </div>

              {product.ingredients && (
                <section className="info-section-item">
                  <h3 className="section-title">
                    <span className="title-indicator"></span>
                    المكونات
                  </h3>
                  <div className="ingredients-flex">
                    {product.ingredients.map((ing, i) => (
                      <span key={i} className="ingredient-chip">
                        {ing}
                      </span>
                    ))}
                  </div>
                </section>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetails;
